+    // ── SpecificityLevel ────────────────────────────────────────────
+
+    #[test]
+    fn test_specificity_priority_values() {
+        assert_eq!(SpecificityLevel::Exact.priority_offset(), 0);
+        assert_eq!(SpecificityLevel::Standard.priority_offset(), 10);
+        assert_eq!(SpecificityLevel::Broad.priority_offset(), 20);
+    }
